// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [showErrors, setShowErrors] = useState(false);
  const totalSteps = 5;

  const isEmailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = showErrors && !name.trim() ? 'Name is required.' : '';
  const emailError = showErrors && !email.trim() ? 'Email is required.' : showErrors && !isEmailValid ? 'Please enter a valid email address.' : '';

  const step1Valid = name.trim().length > 0 && email.trim().length > 0 && isEmailValid;
  const step2Valid = satisfaction !== '';
  const canGoNext = (step === 1 && step1Valid) || (step === 2 && step2Valid) || step === 3 || step === 4;

  const satisfactionOptions = useMemo(
    () =>
      (props.satisfactionLabels || []).map((label, index) => ({
        value: String(index + 1),
        label,
      })),
    [props.satisfactionLabels],
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    setShowErrors(true);
    if (!canGoNext) return;
    setShowErrors(false);
    setStep((prev) => Math.min(totalSteps, prev + 1));
  }, [canGoNext]);

  const handleBack = useCallback(() => {
    setShowErrors(false);
    setStep((prev) => Math.max(1, prev - 1));
  }, []);

  const handleSubmit = useCallback(() => {
    if (!step1Valid || !step2Valid) {
      setStep(!step1Valid ? 1 : 2);
      setShowErrors(true);
      return;
    }
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments: comments.trim(),
    });
  }, [comments, email, features, name, satisfaction, step1Valid, step2Valid, submit]);

  const progressValue = (step / totalSteps) * 100;
  const commentCount = comments.length;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="md"
        border
        radius="lg"
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3}>Multi-step Survey</Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Name"
                value={name}
                onChange={setName}
                required
                error={nameError}
                placeholder="Enter your name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                required
                error={emailError}
                placeholder="Enter your email"
              />
            </Stack>
          )}

          {step === 2 && (
            <RadioGroup
              label="How satisfied are you?"
              value={satisfaction}
              onChange={setSatisfaction}
              options={satisfactionOptions}
              error={showErrors && !step2Valid ? 'Please select a satisfaction rating.' : ''}
            />
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-3)">
              <Text variant="label">Feature interests</Text>
              {(props.featureOptions || []).length === 0 ? (
                <Alert variant="info">No feature options are available.</Alert>
              ) : (
                (props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={(checked) => toggleFeature(feature, checked)}
                  />
                ))
              )}
            </Stack>
          )}

          {step === 4 && (
            <TextArea
              label="Additional comments (optional)"
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
              helperText={`${commentCount}/500 characters`}
              placeholder="Share anything else you'd like us to know"
            />
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review your answers</Heading>
              <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                <Stack gap="var(--ggui-spacing-2)">
                  <Text><Text is="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                  <Text><Text is="span" weight="semibold">Email:</Text> {email || '—'}</Text>
                  <Text>
                    <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                    {satisfaction ? props.satisfactionLabels[Number(satisfaction) - 1] || satisfaction : '—'}
                  </Text>
                  <Text>
                    <Text is="span" weight="semibold">Features:</Text>{' '}
                    {features.length > 0 ? features.join(', ') : 'None selected'}
                  </Text>
                  <Text>
                    <Text is="span" weight="semibold">Comments:</Text>{' '}
                    {comments.trim() ? comments.trim() : 'No comments provided'}
                  </Text>
                </Stack>
              </Card>
            </Stack>
          )}

          <Divider margin="var(--ggui-spacing-2)" />

          <Row justify="between" align="center">
            <Button variant="outline" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>
            {step < totalSteps ? (
              <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit}>
                Submit
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload =
  | { action: 'move'; taskId: string; data: { column: string } }
  | { action: 'edit'; taskId: string; data: { title: string } }
  | { action: 'create'; taskId: string; data: { title: string; priority: 'low' | 'medium' | 'high'; column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [boardTasks, setBoardTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>([]);
  const [addFormByColumn, setAddFormByColumn] = useState<Record<string, boolean>>({});
  const [newTaskTitleByColumn, setNewTaskTitleByColumn] = useState<Record<string, string>>({});
  const [newTaskPriorityByColumn, setNewTaskPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    const validColumnIds = (props.columns || []).map((column) => column.id || '').filter(Boolean);
    const normalizeColumn = (column?: string): string => {
      if (validColumnIds.length === 0) return '';
      return column && validColumnIds.includes(column) ? column : validColumnIds[0];
    };
    const normalized = (props.tasks || []).map((task, index) => ({
      id: task.id || `task-${index + 1}`,
      title: task.title || 'Untitled Task',
      priority: task.priority || 'medium',
      assignee: task.assignee || 'NA',
      column: normalizeColumn(task.column),
      dueDate: task.dueDate,
    }));
    setBoardTasks((prev) => {
      const nextMap = new Map(prev.map((item) => [item.id, item]));
      normalized.forEach((item) => {
        nextMap.set(item.id, {
          ...(nextMap.get(item.id) || item),
          ...item,
          column: normalizeColumn(item.column),
        });
      });
      return Array.from(nextMap.values()).map((item) => ({
        ...item,
        column: normalizeColumn(item.column),
      }));
    });
  }, [props.tasks, props.columns]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) {
      return;
    }
    const incoming = taskChanged.latest.task;
    if (!incoming.id) {
      return;
    }
    const incomingId = incoming.id;
    const validColumnIds = (props.columns || []).map((column) => column.id || '').filter(Boolean);
    const normalizeColumn = (column?: string): string => {
      if (validColumnIds.length === 0) return '';
      return column && validColumnIds.includes(column) ? column : validColumnIds[0];
    };

    setBoardTasks((prev) => {
      const existingIndex = prev.findIndex((item) => item.id === incomingId);
      const action = taskChanged.latest?.action;

      if (action === 'delete') {
        return prev.filter((item) => item.id !== incomingId);
      }

      if (action === 'create') {
        const created = {
          id: incomingId,
          title: incoming.title || 'Untitled Task',
          priority: incoming.priority || 'medium',
          assignee: incoming.assignee || 'NA',
          column: normalizeColumn(incoming.column),
          dueDate: incoming.dueDate,
        };
        if (existingIndex !== -1) {
          return prev.map((item) => (item.id === incomingId ? { ...item, ...created } : item));
        }
        return [...prev, created];
      }

      if (action === 'edit') {
        if (existingIndex === -1) return prev;
        return prev.map((item) =>
          item.id === incomingId
            ? {
                ...item,
                title: incoming.title ?? item.title,
                priority: incoming.priority ?? item.priority,
                assignee: incoming.assignee ?? item.assignee,
                dueDate: incoming.dueDate ?? item.dueDate,
                column: incoming.column !== undefined ? normalizeColumn(incoming.column) : item.column,
              }
            : item
        );
      }

      if (action === 'move') {
        if (existingIndex === -1) return prev;
        return prev.map((item) => (item.id === incomingId ? { ...item, column: normalizeColumn(incoming.column) } : item));
      }

      const upserted = {
        id: incomingId,
        title: incoming.title || (existingIndex !== -1 ? prev[existingIndex].title : 'Untitled Task'),
        priority: incoming.priority || (existingIndex !== -1 ? prev[existingIndex].priority : 'medium'),
        assignee: incoming.assignee || (existingIndex !== -1 ? prev[existingIndex].assignee : 'NA'),
        column: incoming.column !== undefined
          ? normalizeColumn(incoming.column)
          : existingIndex !== -1
            ? normalizeColumn(prev[existingIndex].column)
            : normalizeColumn(undefined),
        dueDate: incoming.dueDate ?? (existingIndex !== -1 ? prev[existingIndex].dueDate : undefined),
      };
      if (existingIndex !== -1) {
        return prev.map((item) => (item.id === incomingId ? { ...item, ...upserted } : item));
      }
      return [...prev, upserted];
    });

  }, [taskChanged.latest, props.columns]);

  const columnIds = useMemo(() => (props.columns || []).map((column) => column.id || '').filter(Boolean), [props.columns]);

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>> = {};
    columnIds.forEach((columnId) => {
      grouped[columnId] = [];
    });
    boardTasks.forEach((task) => {
      const targetColumn = columnIds.includes(task.column) ? task.column : '';
      if (targetColumn && grouped[targetColumn]) {
        grouped[targetColumn].push(task);
      }
    });
    return grouped;
  }, [boardTasks, columnIds]);

  const completedCount = useMemo(() => {
    const doneColumn = (props.columns || []).find((column) => (column.name || '').toLowerCase() === 'done');
    if (!doneColumn || !doneColumn.id) return 0;
    return boardTasks.filter((task) => task.column === doneColumn.id).length;
  }, [boardTasks, props.columns]);

  const updateTaskColumn = useCallback(
    (taskId: string, nextColumn: string) => {
      if (!columnIds.includes(nextColumn)) return;
      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task)));
      taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
    },
    [taskUpdate, columnIds]
  );

  const saveTaskTitle = useCallback(
    (taskId: string) => {
      const safeTitle = editingTitle.trim() || 'Untitled Task';
      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: safeTitle } : task)));
      setEditingTaskId('');
      setEditingTitle('');
      const current = boardTasks.find((task) => task.id === taskId);
      taskUpdate({ action: 'edit', taskId, data: { title: safeTitle } });
    },
    [editingTitle, boardTasks, taskUpdate]
  );

  const createTask = useCallback(
    (columnId: string) => {
      const title = (newTaskTitleByColumn[columnId] || '').trim();
      if (!title) return;
      const taskId = `task-${Date.now()}`;
      const targetColumn = columnIds.includes(columnId) ? columnId : (columnIds[0] || '');
      if (!targetColumn) return;
