}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryColors = useMemo<Record<string, string>>(
    () => ({
      'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
      'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
      'transition metal': 'var(--ggui-color-primary-100, #e0f2fe)',
      lanthanide: 'var(--ggui-color-info-100, #cffafe)',
      actinide: 'var(--ggui-color-success-100, #dcfce7)',
      metalloid: 'var(--ggui-color-primary-200, #bae6fd)',
      'post-transition metal': 'var(--ggui-color-outlineVariant, #e4e4e7)',
      nonmetal: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
      halogen: 'var(--ggui-color-warning-200, #fde68a)',
      'noble gas': 'var(--ggui-color-primary-300, #7dd3fc)',
      'noble-gas': 'var(--ggui-color-primary-300, #7dd3fc)',
      unknown: 'var(--ggui-color-outline, #d4d4d8)',
    }),
    []
  );

  const normalizedElements = useMemo(
    () => (props.elements || []).map((element) => ({
      atomicNumber: element.atomicNumber ?? 0,
      symbol: element.symbol ?? '',
      name: element.name ?? 'Unknown',
      atomicWeight: element.atomicWeight ?? 0,
      category: element.category ?? 'unknown',
      row: element.row ?? 1,
      col: element.col ?? 1,
    })),
    [props.elements]
  );

  useEffect(() => {
    if (normalizedElements.length > 0 && selectedAtomicNumber === null) {
      setSelectedAtomicNumber(normalizedElements[0].atomicNumber);
    }
  }, [normalizedElements, selectedAtomicNumber]);

  const filteredElements = useMemo(() => {
    const lowered = query.trim().toLowerCase();
    if (!lowered) {
      return normalizedElements;
    }
    return normalizedElements.filter(
      (element) =>
        element.name.toLowerCase().includes(lowered) ||
        element.symbol.toLowerCase().includes(lowered)
    );
  }, [normalizedElements, query]);

  const selectedElement = useMemo(
    () => normalizedElements.find((element) => element.atomicNumber === selectedAtomicNumber) ?? null,
    [normalizedElements, selectedAtomicNumber]
  );

  const legendCategories = useMemo(() => {
    const seen: Record<string, boolean> = {};
    const result: string[] = [];
    normalizedElements.forEach((element) => {
      const key = element.category || 'unknown';
      if (!seen[key]) {
        seen[key] = true;
        result.push(key);
      }
    });
    return result;
  }, [normalizedElements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements"
          placeholder="Filter by element name or symbol"
          value={query}
          onChange={setQuery}
          helperText="Type to filter the grid"
        />

        {normalizedElements.length === 0 ? (
          <Alert variant="warning" title="No element data">
            No elements were provided in props.elements.
          </Alert>
        ) : (
          <>
            <Box
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
              padding="var(--ggui-spacing-4)"
            >
              <Box
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
                  gap: 'var(--ggui-spacing-1)',
                }}
              >
                {filteredElements.map((element) => {
                  const bg = categoryColors[element.category] || 'var(--ggui-color-outline, #d4d4d8)';
                  return (
                    <Card
                      key={element.atomicNumber}
                      as={Clickable}
                      onClick={() => setSelectedAtomicNumber(element.atomicNumber)}
                      padding="var(--ggui-spacing-2)"
                      radius="sm"
                      border
                      hoverStyle={{ opacity: 0.9 }}
                      style={{
                        gridColumn: element.col,
                        gridRow: element.row,
                        minHeight: '68px',
                        background: bg,
                        borderColor:
                          selectedAtomicNumber === element.atomicNumber
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-outline, #d4d4d8)',
                        borderWidth: selectedAtomicNumber === element.atomicNumber ? '2px' : '1px',
                        borderStyle: 'solid',
                        position: 'relative',
                      }}
                    >
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                      >
                        {element.atomicNumber}
                      </Text>
                      <Stack align="center" justify="center" style={{ height: '100%' }}>
                        <Text variant="bodyLarge" weight="bold" align="center">
                          {element.symbol}
                        </Text>
                      </Stack>
                    </Card>
                  );
                })}
              </Box>
            </Box>

            {filteredElements.length === 0 && (
              <Alert variant="info" title="No matches">
                No elements match your search query.
              </Alert>
            )}

            <Card padding="var(--ggui-spacing-4)" border shadow="sm">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={4}>Element Details</Heading>
                {selectedElement ? (
                  <>
                    <Text><Text is="span" weight="semibold">Name:</Text> {selectedElement.name}</Text>
                    <Text><Text is="span" weight="semibold">Symbol:</Text> {selectedElement.symbol}</Text>
                    <Text><Text is="span" weight="semibold">Atomic Number:</Text> {selectedElement.atomicNumber}</Text>
                    <Text><Text is="span" weight="semibold">Atomic Weight:</Text> {selectedElement.atomicWeight}</Text>
                    <Text><Text is="span" weight="semibold">Category:</Text> {selectedElement.category}</Text>
                  </>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Select an element to view details.
                  </Text>
                )}
              </Stack>
            </Card>

            <Card padding="var(--ggui-spacing-4)" border shadow="sm">
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Legend</Heading>
                <Row wrap gap="var(--ggui-spacing-2)">
                  {legendCategories.map((category) => (
                    <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                      <Box
                        style={{
                          width: '14px',
                          height: '14px',
                          borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                          border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                          background: categoryColors[category] || 'var(--ggui-color-outline, #d4d4d8)',
                        }}
                      />
                      <Text variant="bodySmall">{category}</Text>
                    </Row>
                  ))}
                </Row>
              </Stack>
            </Card>
          </>
        )}
      </Stack>
    </Container>

  );
}

