    });
  }, [props.product?.stock]);

  const maxQuantity = typeof props.product?.stock === 'number' && props.product.stock > 0 ? props.product.stock : 1;
  const hasStock = typeof props.product?.stock === 'number' ? props.product.stock > 0 : false;
