        return `${currency} ${amount.toFixed(2)}`;
      }
    }
    return amount.toFixed(2);
  }, [props.product?.currency, props.product?.price]);
  const specificationRows = Array.isArray(props.product?.specifications) ? props.product.specifications : [];
