  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages || []);
  const [draft, setDraft] = useState<string>('');
  const [activeTypers, setActiveTypers] = useState<Record<string, boolean>>({});
  const messagesEndRef = useRef<HTMLDivElement | null>(null);

  const previousMessageCountRef = useRef<number>((props.messages || []).length);
  const getMessageKey = useCallback((msg: { sender?: string; text?: string; timestamp?: string }) => {
    return `${msg.sender || 'unknown'}|${msg.timestamp || ''}|${msg.text || ''}`;
  }, []);

  const appendUniqueMessages = useCallback(
    (prev: Array<{ sender?: string; text?: string; timestamp?: string }>, incoming: Array<{ sender?: string; text?: string; timestamp?: string }>) => {
      const seen = new Set(prev.map((item) => getMessageKey(item)));
      const toAdd = incoming.filter((item) => {
        const key = getMessageKey(item);
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
      });
      return toAdd.length > 0 ? [...prev, ...toAdd] : prev;
    },
    [getMessageKey]
  );

