              ) : (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  No one is typing
                </Text>
              )}
            </Stack>
            <Badge variant="primary" size="md">{props.participantCount} participants</Badge>
          </Row>
        </Card>

        <Card border shadow="sm" radius="lg" padding="var(--ggui-spacing-4)">
