type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stocksState, setStocksState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Record<string, boolean>>({});
  const flashTimersRef = useRef<Record<string, ReturnType<typeof setTimeout>>>({});

  useEffect(() => {
    setStocksState(props.stocks || []);
  }, [props.stocks]);

  useEffect(() => {
    const interval = setInterval(() => {
      setNow(new Date());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }

    setStocksState((prev) => {
      const incoming = priceUpdate.latest;
      let found = false;
      const next = prev.map((stock) => {
        if (stock.symbol && incoming.symbol && stock.symbol === incoming.symbol) {
          found = true;
          return {
            ...stock,
            price: incoming.price ?? stock.price,
            change: incoming.change ?? stock.change,
            changePercent: incoming.changePercent ?? stock.changePercent,
          };
        }
        return stock;
      });

      if (!found && incoming.symbol) {
        next.push({
          symbol: incoming.symbol,
          name: incoming.symbol,
          price: incoming.price ?? 0,
          change: incoming.change ?? 0,
          changePercent: incoming.changePercent ?? 0,
        });
      }

      return next;
    });

    setLastUpdated(new Date());

    const symbolKey = priceUpdate.latest.symbol;
    if (symbolKey) {
      if (flashTimersRef.current[symbolKey]) {
        clearTimeout(flashTimersRef.current[symbolKey]);
      }
      setFlashingSymbols((prev) => ({ ...prev, [symbolKey]: true }));
      flashTimersRef.current[symbolKey] = setTimeout(() => {
        setFlashingSymbols((prev) => ({ ...prev, [symbolKey]: false }));
      }, 700);
    }
  }, [priceUpdate.latest]);

  useEffect(() => {
    if (!marketStatus.latest) {
      return;
    }
    if (marketStatus.latest.timestamp) {
      const parsed = new Date(marketStatus.latest.timestamp);
      if (!Number.isNaN(parsed.getTime())) {
        setLastUpdated(parsed);
