              </Text>
            </Stack>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Badge variant={statusBadgeVariant}>
                {marketStatusText}
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Clock: {now.toLocaleTimeString()}
              </Text>
            </Stack>
          </Row>
        </Card>

        {!stocksState || stocksState.length === 0 ? (
          <Card border padding="var(--ggui-spacing-8)" radius="lg">
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stocks available
              </Text>
            </Stack>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocksState.map((stock, index) => {
              const changeValue = stock.change ?? 0;
              const changePercentValue = stock.changePercent ?? 0;
              const isPositive = changeValue >= 0;
              const symbolKey = stock.symbol || `stock-${index}`;
              const trendColor = isPositive
                ? 'var(--ggui-color-success, #16a34a)'
                : 'var(--ggui-color-error, #dc2626)';

              return (
                <Card
                  key={symbolKey}
                  border
                  shadow="sm"
                  padding="var(--ggui-spacing-6)"
                  radius="lg"
                  style={{ borderColor: trendColor }}
                >
                  <Box
                    background={
                      flashingSymbols[symbolKey]
                        ? 'var(--ggui-color-primary-50, #f0f9ff)'
