      completeCallback(payload);
    }
  }, [stepOneValid, stepTwoValid, complete, name, email, avatar, props.avatarOptions, role, emailNotifications, theme, props]);

  useEffect(() => {
    const avatarChoices = props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions : ['😀', '😎', '🚀', '🎨'];
    const roleChoices = props.roleOptions && props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other'];
    setName(props.initialProfile?.name ?? '');
    setEmail(props.initialProfile?.email ?? '');
    setAvatar(
      props.initialProfile?.avatar && avatarChoices.includes(props.initialProfile.avatar)
        ? props.initialProfile.avatar
        : (avatarChoices[0] ?? '😀')
    );
    setRole(
      props.initialProfile?.role && roleChoices.includes(props.initialProfile.role)
        ? props.initialProfile.role
        : ''
    );
    setEmailNotifications(props.initialProfile?.emailNotifications ?? true);
    setTheme(props.initialProfile?.theme === 'dark' || props.initialProfile?.theme === 'light' ? props.initialProfile.theme : 'light');
  }, [props.initialProfile, props.avatarOptions, props.roleOptions]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg" border>
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Stack gap="var(--ggui-spacing-1)">
                <Heading level={3}>Onboarding Wizard</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Step {step} of 3
                </Text>
              </Stack>
              <Badge variant="primary">{Math.round(progressValue)}%</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg" border>
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            <Stack gap="var(--ggui-spacing-6)">
              {step === 1 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Profile Setup</Heading>
                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    placeholder="Enter your full name"
                    required
                    error={name.trim().length === 0 ? 'Name is required' : undefined}
                  />
                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={setEmail}
                    placeholder="you@example.com"
                    required
                    error={email.trim().length > 0 && !emailValid ? 'Please enter a valid email address' : undefined}
                  />

                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Choose Avatar
                    </Text>
                    <Row gap="var(--ggui-spacing-2)" wrap>
                      {(props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions.slice(0, 4) : ['😀', '😎', '🚀', '🎨']).map((option) => (
                        <Card
                          key={option}
                          as={Clickable}
                          onClick={() => setAvatar(option)}
                          padding="var(--ggui-spacing-4)"
                          border
                          shadow="none"
                          radius="md"
                          style={{
                            background: avatar === option ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-surface, #fafafa)',
                            borderColor: avatar === option ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)',
                            transition: 'all 200ms ease',
                            minWidth: '64px',
                            textAlign: 'center',
                          }}
                        >
                          <Text size="2xl" align="center">{option}</Text>
                        </Card>
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              )}

              {step === 2 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={(props.roleOptions && props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((r) => ({ value: r, label: r }))}
                    placeholder="Select your role"
                  />
                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />
                  <Toggle
                    label="Dark theme"
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  />
                </Stack>
              )}

              {step === 3 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Review & Confirm</Heading>
                  <Card padding="var(--ggui-spacing-4)" shadow="none" border radius="md">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row justify="between"><Text variant="label">Name</Text><Text>{name || '—'}</Text></Row>
                      <Row justify="between"><Text variant="label">Email</Text><Text>{email || '—'}</Text></Row>
                      <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '—'}</Text></Row>
                      <Row justify="between"><Text variant="label">Role</Text><Text>{role || '—'}</Text></Row>
                      <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                      <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                    </Stack>
                  </Card>
                </Stack>
              )}

              <Divider margin="var(--ggui-spacing-2)" />
              <Row justify="between" align="center">
                <Button variant="ghost" onPress={handleBack} disabled={step === 1}>
                  Back
                </Button>
                <Row gap="var(--ggui-spacing-2)">
                  {step < 3 && (
                    <Button variant="primary" onPress={handleNext} disabled={!canGoNext}>
                      Next
                    </Button>
                  )}
                  {step === 3 && (
                    <>
                      <Button variant="outline" onPress={() => setStep(2)}>
                        Go Back
                      </Button>
                      <Button variant="primary" onPress={handleComplete} disabled={!stepOneValid}>
                        Complete Setup
                      </Button>
                    </>
                  )}
                </Row>
              </Row>
            </Stack>
          </Box>
        </Card>
      </Stack>
    </Container>
  );
}
